class Solution:
    def findMaxForm(self, strs, m, n):
        # brute force: try all subsets (only practical for small inputs)
        from itertools import combinations
        counts = [(s.count('0'), s.count('1')) for s in strs]
        best = 0
        for r in range(len(strs) + 1):
            for combo in combinations(range(len(strs)), r):
                z = sum(counts[i][0] for i in combo)
                o = sum(counts[i][1] for i in combo)
                if z <= m and o <= n:
                    best = max(best, r)
        return best

